// Operation structure
interface Operation {
  id: string;           // Unique operation ID
  docId: string;        // Document ID
  userId: string;       // Author
  revision: number;     // Document revision when op was created
  timestamp: number;    // Client timestamp
  type: 'insert' | 'delete' | 'retain' | 'format';
  ops: Delta[];         // Array of atomic operations
}

// Delta format (inspired by Quill.js)
interface Delta {
  insert?: string | object;  // Text or embed
  delete?: number;           // Number of chars to delete
  retain?: number;           // Number of chars to skip
  attributes?: object;       // Formatting
}

// Example: Insert "Hello" at position 0
{
  type: 'insert',
  ops: [{ insert: 'Hello' }]
}

// Example: Bold chars 0-5
{
  type: 'format',
  ops: [
    { retain: 5, attributes: { bold: true } },
  ]
}
```

