class CollaborationServer:
    def __init__(self):
        self.document_states = {}  # docId -> DocumentState
        self.operation_history = {}  # docId -> [operations]

    def apply_operation(self, operation: Operation) -> Operation:
        doc_id = operation.doc_id
        state = self.document_states[doc_id]

        # Get operations since client's revision
        concurrent_ops = self.get_ops_since(
            doc_id, 
            operation.revision
        )

        # Transform operation against concurrent operations
        transformed_op = operation
        for concurrent_op in concurrent_ops:
            transformed_op = self.transform(
                transformed_op, 
                concurrent_op
            )

        # Apply transformed operation
        state.apply(transformed_op)

        # Store in history
        transformed_op.revision = state.revision
        self.operation_history[doc_id].append(transformed_op)

        return transformed_op

    def transform(self, op1: Operation, op2: Operation) -> Operation:
        """
        Transform op1 against op2
        Returns new op1 that accounts for op2's changes
