## WebSocket Communication

### Connection Management
```javascript
// Client-side WebSocket handler
class CollabClient {
    constructor(docId, userId) {
        this.docId = docId;
        this.userId = userId;
        this.revision = 0;
        this.pendingOps = [];
        this.inflightOp = null;
        this.ws = null;
    }

    connect() {
        this.ws = new WebSocket(
            `wss://collab.example.com/doc/${this.docId}`
        );

        this.ws.onopen = () => {
            this.sendJoin();
        };

        this.ws.onmessage = (event) => {
            const msg = JSON.parse(event.data);
            this.handleMessage(msg);
        };

        this.ws.onclose = () => {
            this.handleDisconnect();
        };
    }

    // Submit local operation
    submitOperation(op) {
        op.revision = this.revision;

        if (this.inflightOp) {
            // Queue if waiting for ack
            this.pendingOps.push(op);
        } else {
            this.inflightOp = op;
            this.ws.send(JSON.stringify({
                type: 'operation',
                operation: op
            }));
        }
    }

    handleMessage(msg) {
        switch(msg.type) {
            case 'operation':
                this.handleRemoteOperation(msg.operation);
                break;
            case 'ack':
                this.handleAck(msg.revision);
                break;
            case 'cursor':
                this.updateCursor(msg.userId, msg.position);
                break;
        }
    }

    handleRemoteOperation(remoteOp) {
        // Transform against inflight and pending ops
        let transformed = remoteOp;

        if (this.inflightOp) {
            [transformed, this.inflightOp] = this.transformPair(
                transformed, 
                this.inflightOp
            );
        }

        this.pendingOps = this.pendingOps.map(pendingOp => {
            [transformed, pendingOp] = this.transformPair(
                transformed, 
                pendingOp
            );
            return pendingOp;
        });

        // Apply to local document
        this.applyToEditor(transformed);
        this.revision = remoteOp.revision;
    }

    handleAck(serverRevision) {
        this.revision = serverRevision;
        this.inflightOp = null;

        // Send next pending operation
        if (this.pendingOps.length > 0) {
            this.inflightOp = this.pendingOps.shift();
            this.inflightOp.revision = this.revision;
            this.ws.send(JSON.stringify({
                type: 'operation',
                operation: this.inflightOp
            }));
        }
    }
}
```

