### Database Schema
```sql
-- Documents table
CREATE TABLE documents (
    id          UUID PRIMARY KEY,
    title       VARCHAR(500),
    owner_id    UUID REFERENCES users(id),
    created_at  TIMESTAMP,
    updated_at  TIMESTAMP,
    revision    INTEGER DEFAULT 0,
    is_deleted  BOOLEAN DEFAULT FALSE
);

-- Operations log
CREATE TABLE operations (
    id          UUID PRIMARY KEY,
    doc_id      UUID REFERENCES documents(id),
    user_id     UUID REFERENCES users(id),
    revision    INTEGER NOT NULL,
    ops_data    JSONB NOT NULL,      -- Delta operations
    created_at  TIMESTAMP,

    UNIQUE(doc_id, revision)
);

-- Snapshots (periodic full document state)
CREATE TABLE snapshots (
    id          UUID PRIMARY KEY,
    doc_id      UUID REFERENCES documents(id),
    revision    INTEGER NOT NULL,
    content     JSONB NOT NULL,      -- Full document state
    created_at  TIMESTAMP
);

-- Permissions
CREATE TABLE document_permissions (
    doc_id      UUID REFERENCES documents(id),
    user_id     UUID REFERENCES users(id),
    role        ENUM('viewer', 'commenter', 'editor', 'owner'),
    created_at  TIMESTAMP,

    PRIMARY KEY (doc_id, user_id)
);

-- Indexes
CREATE INDEX idx_ops_doc_revision ON operations(doc_id, revision);
CREATE INDEX idx_snapshots_doc ON snapshots(doc_id, revision DESC);
