## Presence & Awareness System

```javascript
// Presence data structure
interface PresenceState {
    userId: string;
    name: string;
    color: string;        // Assigned color for cursor
    cursor: {
        index: number;    // Position in document
        length: number;   // Selection length
    };
    lastSeen: number;     // Timestamp
    isTyping: boolean;
}

// Server-side presence manager
class PresenceManager {
    private presenceMap: Map<string, Map<string, PresenceState>>;
    // docId -> userId -> PresenceState

    updatePresence(docId: string, userId: string, state: Partial<PresenceState>) {
        const docPresence = this.presenceMap.get(docId);
        const current = docPresence.get(userId) || {};

        const updated = {
            ...current,
            ...state,
            lastSeen: Date.now()
        };

        docPresence.set(userId, updated);

        // Broadcast to all users in document
        this.broadcast(docId, {
            type: 'presence',
            userId,
            state: updated
        }, userId); // Exclude sender
    }

    // Clean up stale presence (heartbeat)
    cleanup(docId: string) {
        const threshold = Date.now() - 30000; // 30 seconds
        const docPresence = this.presenceMap.get(docId);

        for (const [userId, state] of docPresence) {
            if (state.lastSeen < threshold) {
                docPresence.delete(userId);
                this.broadcast(docId, {
                    type: 'user_left',
                    userId
                });
            }
        }
    }
}
```

