## Version History

```python
class VersionHistoryService:

    def create_snapshot(self, doc_id: str, revision: int):
        """Create periodic snapshots for fast history access"""
        document = self.reconstruct_document(doc_id, revision)

        snapshot = Snapshot(
            doc_id=doc_id,
            revision=revision,
            content=document.to_json(),
            created_at=datetime.now()
        )

        self.db.save(snapshot)

    def get_document_at_revision(self, doc_id: str, target_revision: int):
        """Reconstruct document at any point in time"""

        # Find nearest snapshot before target revision
        snapshot = self.db.query(
            "SELECT * FROM snapshots "
            "WHERE doc_id = ? AND revision <= ? "
            "ORDER BY revision DESC LIMIT 1",
            doc_id, target_revision
        )

        # Apply operations from snapshot to target
        ops = self.db.query(
            "SELECT * FROM operations "
            "WHERE doc_id = ? AND revision > ? AND revision <= ? "
            "ORDER BY revision ASC",
            doc_id, snapshot.revision, target_revision
        )

        document = Document.from_snapshot(snapshot)
        for op in ops:
            document.apply(op)

        return document

    def get_diff(self, doc_id: str, rev1: int, rev2: int):
        """Get changes between two revisions"""
        doc1 = self.get_document_at_revision(doc_id, rev1)
        doc2 = self.get_document_at_revision(doc_id, rev2)

        return compute_diff(doc1, doc2)
